<?php
namespace App\Http\Controllers\Admin;
use App\Http\Controllers\Controller; use App\Http\Requests\Admin\StoreProjectCategoryRequest; use App\Http\Requests\Admin\UpdateProjectCategoryRequest; use App\Models\ProjectCategory; use Illuminate\Http\RedirectResponse; use Illuminate\Http\Request; use Illuminate\Support\Facades\Cache; use Illuminate\View\View;
class ProjectCategoryController extends Controller { public function index(Request $request): View { $items=ProjectCategory::query()->withCount('projects')->when($request->filled('search'),fn($q)=>$q->where(fn($qq)=>$qq->where('name','like','%'.$request->search.'%')->orWhere('slug','like','%'.$request->search.'%')))->when($request->filled('status'),fn($q)=>$q->where('status',(bool)$request->integer('status')))->ordered()->paginate(15)->withQueryString(); return view('admin.pages.project-categories.index',compact('items')); } public function create(): View { return view('admin.pages.project-categories.form',['item'=>new ProjectCategory()]); } public function store(StoreProjectCategoryRequest $request): RedirectResponse { ProjectCategory::create($this->payload($request->validated())); $this->clearCache(); return redirect()->route('admin.project-categories.index')->with('success','Project category created successfully.'); } public function edit(ProjectCategory $projectCategory): View { return view('admin.pages.project-categories.form',['item'=>$projectCategory]); } public function update(UpdateProjectCategoryRequest $request, ProjectCategory $projectCategory): RedirectResponse { $projectCategory->update($this->payload($request->validated())); $this->clearCache(); return redirect()->route('admin.project-categories.index')->with('success','Project category updated successfully.'); } public function destroy(ProjectCategory $projectCategory): RedirectResponse { if ($projectCategory->projects()->exists()) { return back()->withErrors(['project_category'=>'This category has projects and cannot be deleted. Please reassign or remove the projects first.']); } $projectCategory->delete(); $this->clearCache(); return back()->with('success','Project category deleted successfully.'); } private function payload(array $data): array { $data['status']=(bool)($data['status']??false); $data['sort_order']=(int)($data['sort_order']??0); return $data; } private function clearCache(): void { foreach(['project_categories_active_ordered','projects_active_ordered','projects_featured_ordered','homepage_projects_featured','homepage_sections'] as $key) Cache::forget($key); } }
